#include "interface.h"
#include <omp.h>
#include <cstdint>
#include <vector>

namespace {

uint64_t checksum_u32(const std::vector<uint32_t>& data) {
  uint64_t hash = 1469598103934665603ULL;
  for (uint32_t v : data) {
    hash ^= static_cast<uint64_t>(v);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t jacobi_checksum(const std::vector<uint32_t>& input, int rows, int cols, int steps) {
  if (rows <= 0 || cols <= 0 || steps <= 0) return checksum_u32(input);

  std::vector<uint32_t> a = input;
  std::vector<uint32_t> b = a;
  const std::size_t cols_s = static_cast<std::size_t>(cols);
  const bool has_inner = rows >= 3 && cols >= 3;
  if (!has_inner) return checksum_u32(a);

  const int inner_row_end = rows - 1;
  const int inner_col_end = cols - 1;

  for (int step = 0; step < steps; ++step) {
    #pragma omp parallel for schedule(static)
    for (int row = 1; row < inner_row_end; ++row) {
      const std::size_t row_base = static_cast<std::size_t>(row) * cols_s;
      for (int col = 1; col < inner_col_end; ++col) {
        const std::size_t idx = row_base + static_cast<std::size_t>(col);
        b[idx] = (a[idx] * 4u + a[idx - 1] + a[idx + 1] + a[idx - cols_s] + a[idx + cols_s]) / 8u;
      }
    }
    a.swap(b);
  }

  return checksum_u32(a);
}
